                                    <div class="card-body">
                                        <div class="chart-container">
                                            <canvas id="main"></canvas>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>

                        <!-- Secondary Chart Row -->
                        <div class="row secondary-chart-row">
                            <div class="col-12">
                                <div class="chart-card">
                                    <div class="card-header">
                                        <h5><i class="fas fa-chart-bar me-2 text-primary"></i>Consommation par Type de Client (Mensuelle)</h5>
