                    </div>
                </div>
            </div>
        </div>
    </div>

    <script src="{% static 'datatable/jquery/jquery-3.7.0.min.js' %}"></script>
    <script src="{% static 'fontawesome/js/all.min.js' %}"></script>
    <script src="{% static 'chiffre_espacement.js' %}"></script>
    <script src="https://cdnjs.cloudflare.com/ajax/libs/Chart.js/3.9.1/chart.min.js"></script>
    <script src="https://cdnjs.cloudflare.com/ajax/libs/date-fns/2.0.0-alpha0/date_fns.min.js"></script>
    <script src="https://cdnjs.cloudflare.com/ajax/libs/chartjs-plugin-datalabels/2.2.0/chartjs-plugin-datalabels.min.js"></script>
    <script src="https://cdnjs.cloudflare.com/ajax/libs/chartjs-adapter-date-fns/3.0.0/chartjs-adapter-date-fns.min.js"></script>
    <script>
        // Variables CSS pour Chart.js - Nouvelles couleurs Material Design
        const primaryColor = '#1976d2';
        const successColor = '#2e7d32';
        const warningColor = '#ed6c02';
        const dangerColor = '#d32f2f';
        const infoColor = '#0288d1';

        let modernColors = [
            '#1976d2', '#2e7d32', '#0288d1', '#ed6c02', '#d32f2f',
            '#9c27b0', '#ff9800', '#4caf50', '#ef5350', '#ba68c8',
            '#343a40', '#42a5f5', '#4caf50', '#ff9800', '#ef5350'
        ];

        // Configuration globale pour Chart.js
        Chart.defaults.font.family = 'Inter';
        Chart.defaults.color = '#6b7280';
        Chart.defaults.plugins.legend.labels.usePointStyle = true;
        Chart.defaults.plugins.legend.labels.boxWidth = 8;
        Chart.defaults.plugins.legend.labels.padding = 15;

        // Animation d'entrée pour les chiffres
        function animateValue(element, start, end, duration) {
            let startTimestamp = null;
            const step = (timestamp) => {
                if (!startTimestamp) startTimestamp = timestamp;
                const progress = Math.min((timestamp - startTimestamp) / duration, 1);
                const current = Math.floor(progress * (end - start) + start);
                element.textContent = formatNumberWithSpaces(current);
                if (progress < 1) {
                    window.requestAnimationFrame(step);
                }
            };
            window.requestAnimationFrame(step);
        }

        function formatNumberWithSpaces(number) {
            return number.toString().replace(/\B(?=(\d{3})+(?!\d))/g, " ");
        }

        // Données pour le graphique doughnut
        const dataValues = [
            {% for commune in communes %}
                {{ commune.total_conso }},
            {% endfor %}
        ];

        if (dataValues.length > 0) {
            let Recap = document.getElementById('RecapConso').getContext('2d');
            const total = dataValues.reduce((a, b) => a + b, 0);
            const percentageValues = dataValues.map(value => ((value / total) * 100).toFixed(1));

            new Chart(Recap, {
                type: 'doughnut',
                data: {
                    labels: [
                        {% for commune in communes %}
                            '{{ commune.region.region }} {{ commune.commune }}',
                        {% endfor %}
                    ],
                    datasets: [{
                        label: 'Consommation par Réseaux',
                        data: percentageValues,
                        backgroundColor: modernColors,
                        borderWidth: 0,
                        hoverBorderWidth: 3,
                        hoverBorderColor: '#ffffff'
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    plugins: {
                        legend: {
                            position: 'bottom',
                            labels: {
                                padding: 20,
                                font: {
                                    size: 12,
                                    weight: '500'
                                }
                            }
                        },
                        tooltip: {
                            backgroundColor: 'rgba(0, 0, 0, 0.8)',
                            titleColor: '#ffffff',
                            bodyColor: '#ffffff',
                            borderColor: primaryColor,
                            borderWidth: 1,
                            cornerRadius: 8,
                            callbacks: {
                                label: function(context) {
                                    return context.label + ': ' + context.parsed + '%';
                                }
                            }
                        }
                    },
                    cutout: '60%'
                }
            });
        }

        // Graphique d'évolution
        let EvoConso = document.getElementById('EvoConso').getContext('2d');
        new Chart(EvoConso, {
            type: 'line',
            data: {
                datasets: [
                    {% for row in evo_conso %}
                    {
                        label: '{{ row.commune }}',
                        data: [
                            {% for list in row.data %}
                            {
                                x: '{% if list.mois_releve < 10 %}0{% endif %}{{ list.mois_releve }}/{{ list.annee_releve }}',
                                y: {{ list.total_conso }}
                            },
                            {% endfor %}
                        ],
                        backgroundColor: modernColors[{{ forloop.counter0 }} % modernColors.length] + '20',
                        borderColor: modernColors[{{ forloop.counter0 }} % modernColors.length],
                        borderWidth: 3,
                        tension: 0.4,
                        fill: true,
                        pointBackgroundColor: modernColors[{{ forloop.counter0 }} % modernColors.length],
                        pointBorderColor: '#ffffff',
                        pointBorderWidth: 2,
                        pointRadius: 6,
                        pointHoverRadius: 8
                    },
                    {% endfor %}
                ]
            },
            options: {
                responsive: true,
                maintainAspectRatio: false,
                interaction: {
                    intersect: false,
                    mode: 'index'
                },
                scales: {
                    y: {
                        beginAtZero: true,
                        grid: {
                            color: '#f1f5f9'
                        },
                        ticks: {
                            font: {
                                size: 11
                            }
                        }
                    },
                    x: {
                        grid: {
                            color: '#f1f5f9'
                        },
                        ticks: {
                            font: {
                                size: 11
                            }
                        }
                    }
                },
                plugins: {
                    legend: {
                        position: 'top'
                    },
                    tooltip: {
                        backgroundColor: 'rgba(0, 0, 0, 0.8)',
                        titleColor: '#ffffff',
                        bodyColor: '#ffffff',
                        borderColor: primaryColor,
                        borderWidth: 1,
                        cornerRadius: 8
                    }
                }
            }
        });

        // Graphique de paiement
        let paiement = document.getElementById('paiement').getContext('2d');
        let paymentData = {
            labels: [],
            datasets: [
                {
                    label: 'Factures payées',
                    backgroundColor: successColor,
                    borderRadius: 6,
                    data: []
                },
                {
                    label: 'Factures impayées',
                    backgroundColor: dangerColor,
                    borderRadius: 6,
                    data: []
                }
            ]
        };

        {% for facture in factures %}
            paymentData.labels.push('{% if facture.mois < 10 %}0{% endif %}{{ facture.mois }}/{{ facture.annee }}');
            paymentData.datasets[0].data.push('{{ facture.nombre_factures_payees }}');
            paymentData.datasets[1].data.push('{{ facture.nombre_factures_impayees }}');
        {% endfor %}

        new Chart(paiement, {
            type: 'bar',
            data: paymentData,
            options: {
                responsive: true,
                maintainAspectRatio: false,
                scales: {
                    y: {
                        beginAtZero: true,
                        grid: {
                            color: '#f1f5f9'
                        }
                    },
                    x: {
                        grid: {
                            display: false
                        }
                    }
                },
                plugins: {
                    legend: {
                        position: 'top'
                    },
                    tooltip: {
                        backgroundColor: 'rgba(0, 0, 0, 0.8)',
                        titleColor: '#ffffff',
                        bodyColor: '#ffffff',
                        cornerRadius: 8
                    }
                }
            }
        });

        // Graphique Main Courante
        let main = document.getElementById('main').getContext('2d');
        let mainData = {
            labels: [],
            datasets: [
                {
                    label: 'Non traitées',
                    backgroundColor: warningColor,
                    borderRadius: 6,
                    data: []
                },
                {
                    label: 'Réalisées',
                    backgroundColor: successColor,
                    borderRadius: 6,
                    data: []
                },
                {
                    label: 'En cours',
                    backgroundColor: infoColor,
                    borderRadius: 6,
                    data: []
                }
            ]
        };

        {% for item in main_courantes %}
            mainData.labels.push('{% if item.mois < 10 %}0{% endif %}{{ item.mois }}/{{ item.annee }}');
            mainData.datasets[0].data.push('{{ item.nb_non_traite }}');
            mainData.datasets[1].data.push('{{ item.nb_realise }}');
            mainData.datasets[2].data.push('{{ item.nb_en_cours }}');
        {% endfor %}

        new Chart(main, {
            type: 'bar',
            data: mainData,
            options: {
                responsive: true,
                maintainAspectRatio: false,
                scales: {
                    y: {
                        beginAtZero: true,
                        grid: {
                            color: '#f1f5f9'
                        }
                    },
                    x: {
                        grid: {
                            display: false
                        }
                    }
                },
                plugins: {
                    legend: {
                        position: 'top'
                    },
                    tooltip: {
                        backgroundColor: 'rgba(0, 0, 0, 0.8)',
                        titleColor: '#ffffff',
                        bodyColor: '#ffffff',
                        cornerRadius: 8
                    }
                }
            }
        });

        // Graphique de consommation par type de client
        let typeClientConso = document.getElementById('typeClientConso').getContext('2d');
        let typeClientData = {
            labels: [],
            datasets: []
        };

        let dataByMonth = {};
        let typesClient = new Set();

        {% for conso in types_client_conso %}
            (function() {
                let monthKey = '{% if conso.mois < 10 %}0{% endif %}{{ conso.mois }}/{{ conso.annee }}';
                let typeClient = '{{ conso.designation_client }}';
                let consommation = {{ conso.conso_mensuelle }};

                if (!dataByMonth[monthKey]) {
                    dataByMonth[monthKey] = {};
                }
                dataByMonth[monthKey][typeClient] = consommation;
                typesClient.add(typeClient);
            })();
        {% endfor %}

        typeClientData.labels = Object.keys(dataByMonth).sort();
        let colorIndex = 0;

        typesClient.forEach(function(typeClient) {
            let dataset = {
                label: typeClient,
                backgroundColor: modernColors[colorIndex % modernColors.length],
                borderRadius: 6,
                data: []
            };

            typeClientData.labels.forEach(function(monthKey) {
                let value = dataByMonth[monthKey][typeClient] || 0;
                dataset.data.push(value);
            });

            typeClientData.datasets.push(dataset);
            colorIndex++;
        });

        new Chart(typeClientConso, {
            type: 'bar',
            data: typeClientData,
            options: {
                responsive: true,
                maintainAspectRatio: false,
                scales: {
                    y: {
                        beginAtZero: true,
                        title: {
                            display: true,
                            text: 'Consommation (m³)',
                            font: {
                                weight: '600'
                            }
                        },
                        grid: {
                            color: '#f1f5f9'
                        }
                    },
                    x: {
                        title: {
                            display: true,
                            text: 'Mois/Année',
                            font: {
                                weight: '600'
                            }
                        },
                        grid: {
                            display: false
                        }
                    }
                },
                plugins: {
                    legend: {
                        position: 'top'
                    },
                    tooltip: {
                        backgroundColor: 'rgba(0, 0, 0, 0.8)',
                        titleColor: '#ffffff',
                        bodyColor: '#ffffff',
                        borderColor: primaryColor,
                        borderWidth: 1,
                        cornerRadius: 8
                    }
                }
            }
        });

        // Intersection Observer pour animations au scroll
        const observerOptions = {
            threshold: 0.1,
            rootMargin: '0px 0px -50px 0px'
        };

        const observer = new IntersectionObserver((entries) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    entry.target.style.opacity = '1';
                    entry.target.style.transform = 'translateY(0)';
                }
            });
        }, observerOptions);

        // Observer tous les éléments chart-container
        document.querySelectorAll('.chart-container').forEach(el => {
            observer.observe(el);
        });
    </script>
</body>
</html>
